member.example:
Bind an ObservableListViewModelBinder using a serialized field — the target factory is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ObservableListViewModelBinder _items;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public ObservableList<IViewModel> _items;
    }

Bind an ObservableListViewModelBinder<T> by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ObservableListViewModelBinder<ItemView> _items
            = new(new PrefabViewFactory<ItemView>());
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public ObservableList<IViewModel> _items;
    }

Bind an ObservableListViewModelBinder<T, TViewFactory> by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ObservableListViewModelBinder<ItemView, CustomViewFactory> _items
            = new(new CustomViewFactory());
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public ObservableList<IViewModel> _items;
    }
